import React, {
    useContext
} from "react";

import {
    CartContext
} from "../contexts/CartContext";

import {
    Link
} from "react-router-dom";


function CartPage() {

    const {

        cartItems,

        removeFromCart,

        increaseQuantity,

        decreaseQuantity,

        totalPrice

    } = useContext(
        CartContext
    );


    return (

        <div>

            <h1>

                Shopping Cart

            </h1>

            {

                cartItems.map(

                    item => (

                        <div
                            key={item.id}
                        >

                            <h3>

                                {item.title}

                            </h3>

                            <p>

                                ${item.price}

                            </p>

                            <p>

                                Quantity :
                                {item.quantity}

                            </p>

                            <button

                                onClick={() =>
                                    increaseQuantity(
                                        item.id
                                    )
                                }

                            >

                                +

                            </button>

                            <button

                                onClick={() =>
                                    decreaseQuantity(
                                        item.id
                                    )
                                }

                            >

                                -

                            </button>

                            <button

                                onClick={() =>
                                    removeFromCart(
                                        item.id
                                    )
                                }

                            >

                                Remove

                            </button>

                        </div>

                    )

                )

            }

            <h2>

                Total :

                ${totalPrice.toFixed(2)}

            </h2>

            <Link to="/checkout">

                Proceed To Checkout

            </Link>

        </div>

    );

}

export default CartPage;
